mapper.select:
SELECT *
  FROM TW_TREE
 WHERE HOSP_CD = #{hospCd}
   AND TAB_ID = #{tabId}
   AND GRP_CD = #{grpCd}
   AND PARENT_ID = #{parentId}
   AND USE_YN = 'Y'
 ORDER BY SORT_ORD

SELECT *
  FROM TW_TREE
 WHERE HOSP_CD = #{hospCd}
   AND TAB_ID = #{tabId}
   AND USE_YN = 'Y'
 ORDER BY NODE_ID

mapper.update:
UPDATE TW_TREE
   SET NODE_NM = #{nodeNm}
     , NODE_DESC = #{nodeDesc}
     , SORT_ORD = #{sortOrd}
 WHERE HOSP_CD = #{hospCd}
   AND TAB_ID = #{tabId}
   AND GRP_CD = #{grpCd}
   AND NODE_ID = #{nodeId}

UPDATE TW_TREE
   SET USE_YN = 'N'
 WHERE HOSP_CD = #{hospCd}
   AND TAB_ID = #{tabId}
   AND GRP_CD = #{grpCd}
   AND NODE_ID = #{nodeId}

