UPDATE TW_QPS
   SET QPS_NM = #{qpsNm}
     , NOTE = #{note}
     , UPD_DT = NOW()
     , UPD_USER = #{updUser}
 WHERE HOSP_CD = #{hospCd}
   AND QPS_CD = #{qpsCd}

