SELECT HOSP_CD, REF_CD, REF_SEQ, REF_VAL, NOTE, USE_YN, REG_DT, REG_USER
  FROM TW_REF
 WHERE HOSP_CD = #{hospCd}
   AND REF_CD = #{refCd}
 ORDER BY REF_SEQ

mapper.update:
UPDATE TW_REF
   SET REF_VAL = #{refVal}
     , NOTE = #{note}
     , USE_YN = #{useYn}
     , UPD_DT = NOW()
     , UPD_USER = #{updUser}
 WHERE HOSP_CD = #{hospCd}
   AND REF_CD = #{refCd}
   AND REF_SEQ = #{refSeq}

mapper.delete:
